data_structures_08.complete:
import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        Map<String, Integer> inventaire = new HashMap<>();

        // Insertion Clé-Valeur
        inventaire.put("Or", 500);
        inventaire.put("Bois", 12);

        // Accès sécurisé
        if (inventaire.containsKey("Or")) {
            int quantite = inventaire.get("Or");
            System.out.println("Or dispo : " + quantite);
        }

        // Parcours
        for (Map.Entry<String, Integer> entree : inventaire.entrySet()) {
            System.out.println(entree.getKey() + " -> " + entree.getValue());
        }
    }
}

